mapper.select:
/* courtDpstMapper.getCourtDpstList */
SELECT TO_CHAR(TO_DATE(INOUT.INOUT_DTTM, 'YYYYMMDD'), 'YYYY-MM-DD') AS INOUT_DT, F_GET_KT_CODE_NM('PPS_VAC', 'BANK_CODE', ACCT.VAC_BANK_CD) AS VAC_BANK_NM, ACCT.VAC_ID, TO_CHAR(TO_DATE(ACCT.DCLR_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS VAC_DT, RSV.CSTMR_NAME, FN_GET_CODENM('MSP0031', RSV.CR_TP ) AS CR_TP, RSV.CR_COMP, RSV.NO_JUDG, RSV.RB_PRID, INOUT.INOUT_PRIC AS TOTAL_PRIC, INOUT.INOUT_NAME, INOUT.INOUT_ORDER FROM (SELECT CSTMR_NAME, CSTMR_RRN, CR_TP, CR_COMP, NO_JUDG, RB_PRID, CR_SEQ FROM MSP_COURT_RCV ) RSV, (SELECT A.VAC_BANK_CD, A.VAC_ID, A.CR_SEQ, A.DCLR_DATE FROM MSP_COURT_RCV_ACCT A, (SELECT CR_SEQ, MAX(CR_ACCT_SEQ) AS ACCT_SEQ FROM MSP_COURT_RCV_ACCT GROUP BY CR_SEQ ) B WHERE A.CR_SEQ = B.CR_SEQ AND A.CR_ACCT_SEQ = B.ACCT_SEQ ) ACCT, (SELECT INOUT_DTTM, INOUT_PRIC, INOUT_NAME, INOUT_ORDER, CR_SEQ, CR_INOUT_SEQ FROM MSP_COURT_RCV_INOUT ) INOUT WHERE RSV.CR_SEQ = ACCT.CR_SEQ (+) AND RSV.CR_SEQ = INOUT.CR_SEQ
AND TO_CHAR(TO_DATE(INOUT.INOUT_DTTM, 'YYYYMMDD'), 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND ACCT.VAC_ID = #{searchVal}
AND RSV.CSTMR_RRN = #{searchRrn}
ORDER BY INOUT.INOUT_DTTM DESC, INOUT.CR_INOUT_SEQ DESC

