AND TO_CHAR(TO_DATE(INOUT.INOUT_DTTM, 'YYYYMMDD'), 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND ACCT.VAC_ID = #{searchVal}
AND RSV.CSTMR_RRN = #{searchRrn}
ORDER BY INOUT.INOUT_DTTM DESC, INOUT.CR_INOUT_SEQ DESC
